// TestPrefixTransformerMatch tests that PrefixTransformer correctly matches and strips prefixes
func TestPrefixTransformerMatch(t *testing.T) {
	tests := []struct {
		name            string
		prefix          []byte
		data            []byte
		shouldMatch     bool
		expectedStripped []byte
	}{
		{
			name:            "prefix matches at start",
			prefix:          []byte("enc:"),
			data:            []byte("enc:encrypted-data"),
			shouldMatch:     true,
			expectedStripped: []byte("encrypted-data"),
		},
		{
			name:            "prefix does not match",
			prefix:          []byte("other:"),
			data:            []byte("enc:encrypted-data"),
			shouldMatch:     false,
		},
		{
			name:            "empty prefix always matches",
			prefix:          []byte{},
			data:            []byte("any-data"),
			shouldMatch:     true,
			expectedStripped: []byte("any-data"),
		},
		{
			name:            "prefix is exact match",
			prefix:          []byte("test"),
			data:            []byte("test"),
			shouldMatch:     true,
			expectedStripped: []byte{},
		},
		{
			name:            "data shorter than prefix",
			prefix:          []byte("prefix"),
			data:            []byte("pre"),
			shouldMatch:     false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			matched := bytes.HasPrefix(tt.data, tt.prefix)
			if matched != tt.shouldMatch {
				t.Errorf("expected match %v, got %v", tt.shouldMatch, matched)
			}
			if matched && !bytes.Equal(tt.data[len(tt.prefix):], tt.expectedStripped) {
				t.Errorf("expected stripped data %v, got %v", tt.expectedStripped, tt.data[len(tt.prefix):])
			}
		})
	}
}

// TestTransformerRoundTrip tests basic encrypt-decrypt round trip
func TestTransformerRoundTrip(t *testing.T) {
	tests := []struct {
		name     string
		data     []byte
		ctx      context.Context
		dataCtx  Context
	}{
		{
			name:    "simple round trip",
			data:    []byte("secret-data"),
			ctx:     context.Background(),
			dataCtx: DefaultContext([]byte("auth-data")),
		},
		{
			name:    "empty data round trip",
			data:    []byte{},
			ctx:     context.Background(),
			dataCtx: nil,
		},
		{
			name:    "with request context",
			data:    []byte("test-value"),
			ctx:     genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "pods"}),
			dataCtx: DefaultContext([]byte("pod-auth")),
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			transformer := &roundTripTransformer{}

			// Transform to storage
			encrypted, err := transformer.TransformToStorage(tt.ctx, tt.data, tt.dataCtx)
			if err != nil {
				t.Fatalf("TransformToStorage failed: %v", err)
			}

			// Transform from storage
			decrypted, stale, err := transformer.TransformFromStorage(tt.ctx, encrypted, tt.dataCtx)
			if err != nil {
				t.Fatalf("TransformFromStorage failed: %v", err)
			}

			// Verify round trip
			if !bytes.Equal(decrypted, tt.data) {
				t.Errorf("round trip failed: expected %v, got %v", tt.data, decrypted)
			}

			// Verify not marked as stale for first transformer
			if stale {
				t.Errorf("expected stale=false, got stale=true")
			}
		})
	}
}

